               '    position: absolute;',
               '    background: #6c5ce7;',
               '    border-radius: 2px;',
               '    transition: background 0.2s ease;',
               '}',
               '.orb-add-icon::before {',
               '    width: 2px;',
               '    height: 16px;',
               '    left: 7px;',
               '    top: 0;',
               '}',
               '.orb-add-icon::after {',
               '    width: 16px;',
